insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'chiyoda'), 'tokyo-chiyoda-elderly-diapers', '千代田区 紙おむつの支給・費用助成（高齢者・要介護者向け）', '千代田区が、在宅で要介護1以上などの常時紙おむつを必要とする高齢者向けに、毎月1回自宅へ紙おむつを配達する現物支給を行う制度（公式で確認）。入院中で病院指定のおむつを使う場合は現金助成も用意されている。金額・自己負担・対象要件は変更の可能性があるため、必ず千代田区公式ページで最新情報を確認のこと。', '千代田区では、在宅で要介護1以上などにより常時紙おむつが必要な高齢者に、紙おむつを毎月自宅まで届ける支援（現物支給）があります。カタログから商品を選んで注文すると、毎月一定額（公式では1か月10,600円・税込以内）までは購入価格の1割の自己負担で利用できるとされています。入院中で病院指定のおむつを使う方には現金での助成が用意されている場合があります。対象や金額は変わる可能性があるため、利用を検討する際は千代田区の公式ページや在宅支援課に確認してください。', 'service', '千代田区に住所があり、在宅で要介護1以上などにより常時紙おむつの着用を必要とする高齢者が対象となる可能性がある（65歳以上で入院中の方が現金助成の対象となる場合もある）。具体的な対象要件は公式で確認のこと。', '公式によると、現物支給は1か月あたり10,600円（税込）以内は購入価格の1割負担で利用でき、超過分は全額自己負担、生活保護世帯は10,600円以内が無料とされる。入院中の現金助成は月13,200円が上限とされる。金額は変更の可能性があるため公式で確認のこと。', '公式ページ上に明確な申請期限の記載は確認できなかった。随時申請の可能性があるが、詳細は区に確認のこと。', 'オンライン申請（区のポータルサイト）または申請書による手続きが可能とされる。利用時はカタログから商品を選び指定業者へ注文し、毎月自宅等へ配達される。詳細・最新の手続きは千代田区公式ページまたは在宅支援課に確認のこと。', '申請書のほか、おむつ指定証明書や調査・申告に関する書類が必要となる場合がある。必要書類は申請区分により異なるため公式で確認のこと。', TRUE, '千代田区 保健福祉部 在宅支援課', '03-6265-6482・6486', 'https://www.city.chiyoda.lg.jp/koho/kenko/koresha/dokuji-kaigo/kami.html', 'https://www.city.chiyoda.lg.jp/koho/kenko/koresha/dokuji-kaigo/kami.html', '千代田区ホームページ - 紙おむつ', '2026-06-24', 'high', ARRAY['benefitAmountText', 'applicationDeadlineText', 'requiredDocumentsText', 'targetPeople']::text[], '本情報は千代田区公式ページ（確認日2026-06-24）に基づく概要であり、金額・対象・手続きは変更されることがある。申請の可否や受給は審査により決まるため、利用前に必ず千代田区公式の最新情報および在宅支援課への確認のこと。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
insert into public.support_program_categories (support_program_id, category_id) select sp.id, c.id from public.support_programs sp, public.categories c where sp.slug = 'tokyo-chiyoda-elderly-diapers' and c.slug = 'nursing-care' on conflict do nothing;
