insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot elderly-diapers import', '{"slug":"tokyo-chiyoda-elderly-diapers","status":"published","title":"千代田区 紙おむつの支給・費用助成（高齢者・要介護者向け）","officialUrl":"https://www.city.chiyoda.lg.jp/koho/kenko/koresha/dokuji-kaigo/kami.html","topic":"elderly-diapers"}'::jsonb, 'pilot:tokyo-chiyoda-elderly-diapers:dG9reW8tY2hpeW9kYS1lbGRlcmx5LWRpYXBlcnN8' from public.support_programs sp where sp.slug='tokyo-chiyoda-elderly-diapers' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'chuo'), 'tokyo-chuo-elderly-diapers', '紙おむつ等支給（高齢者）', '中央区の在宅高齢者向けに、紙おむつ等を現物支給する区独自の制度。介護保険の要介護2以上と認定され、常時寝たきりまたは認知症で失禁状態にあり、介護保険施設に入所していない方が対象となる可能性があります。病院や有料老人ホーム指定のおむつのみ使用が必要な場合は、月7,000円を限度とする費用助成も用意されています。具体的な対象要件・支給量・利用者負担は公式でご確認ください。', '中央区では、在宅で寝たきりや認知症などにより常におむつが必要な高齢者に、紙おむつを届ける制度があります。介護保険で要介護2以上の認定を受け、介護保険施設に入所していない方が対象になる可能性があります。区役所4階の高齢者福祉課などで申請でき、郵送申請もできます。病院などで指定のおむつしか使えない場合は、月7,000円までの費用助成もあります。金額や自己負担は条件によって変わるため、公式ページや問い合わせ先でご確認ください。', 'service', '介護保険の要介護2以上と認定され、常時寝たきりまたは認知症でかつ失禁状態にあり、介護保険施設に入所していない在宅の高齢者が対象となる可能性があります。詳しい対象要件は中央区公式でご確認ください。', '現物支給が基本で、月40〜70点以内（1点100円換算で月4,000〜7,000円相当）の範囲で指定商品から注文します。病院・有料老人ホーム指定のおむつのみ使用が必要な場合は月7,000円を限度とする費用助成があります。利用者負担は利用点数と住民税課税状況により異なります（公式で要確認）。', '公式ページに明記なし。詳細は問い合わせ先にご確認ください。', '区役所4階の高齢者福祉課、各特別出張所、おとしより相談センターで申請します。来庁が難しい場合は郵送での申請も可能です。', '紙おむつ支給の場合は申請書・注文票。おむつ代助成の場合は申請書・指定おむつ等使用証明書・支払金口座振替登録依頼書が必要とされています（公式で要確認）。', FALSE, '中央区 福祉保健部 高齢者福祉課 高齢者サービス係', '03-3546-5355', NULL, 'https://www.city.chuo.lg.jp/a0028/kenkouiryou/koureikaigo/zaitakuiryou/zaitakushienservice/nintei/omutu.html', '紙おむつ等支給 - 中央区', '2026-06-24', 'high', ARRAY['benefitAmountText', 'applicationDeadlineText', '利用者負担額', '要介護度・所得区分による支給量・負担の変動']::text[], '対象要件・支給量・利用者負担額は中央区が独自に定めており、制度改正等で変わる場合があります。最新の内容は必ず中央区公式ページまたは高齢者福祉課にご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
