insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot elderly-diapers import', '{"slug":"tokyo-chuo-elderly-diapers","status":"published","title":"紙おむつ等支給（高齢者）","officialUrl":"https://www.city.chuo.lg.jp/a0028/kenkouiryou/koureikaigo/zaitakuiryou/zaitakushienservice/nintei/omutu.html","topic":"elderly-diapers"}'::jsonb, 'pilot:tokyo-chuo-elderly-diapers:dG9reW8tY2h1by1lbGRlcmx5LWRpYXBlcnN857SZ' from public.support_programs sp where sp.slug='tokyo-chuo-elderly-diapers' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'minato'), 'tokyo-minato-elderly-diapers', '高齢者紙おむつの給付（港区）', '港区が実施する、在宅で寝たきりまたは失禁状態にあり要支援1以上の認定を受けた高齢者向けの紙おむつ現物支給制度。月1回、パンフレット掲載商品から所定の範囲内で自宅へ配送される（公式で確認）。医療機関に入院中・有料老人ホーム等に入所中の人には別途「おむつ代の助成」（費用助成）が用意されている。対象や金額の詳細は港区公式ページで確認が必要。', '港区にお住まいで、寝たきりや失禁の状態にあり、介護保険で要支援1以上と認定された方は、紙おむつを毎月自宅に届けてもらえる可能性があります。施設に入所・入院中の方は、代わりにおむつ代の費用助成が受けられる場合があります。対象になるかどうかや自己負担額などは、港区の公式案内でご確認ください。', 'service', '港区に住み、寝たきりまたは失禁状態にあり、介護保険法の要介護認定で要支援1以上の認定を受けて在宅で生活している高齢者が対象となる可能性があります（特別養護老人ホーム等の施設入所者・入院患者は対象外。詳細は公式で確認）。', '現物支給。公式案内によれば月1回、パンフレット掲載商品から所定の点数（120点）までを自宅へ配送し、自己負担は月額500円とされています（金額・支給量は年度や公式で要確認）。', '公式ページに具体的な申請期限の記載は確認できませんでした。', '電子申請（オンライン）、郵送、窓口来所のいずれかで申請できるとされています。窓口は港区 保健福祉支援部 高齢者支援課 在宅支援係のほか、各地区総合支所区民課保健福祉係・各地区高齢者相談センターでも受付。', '申請人を確認できるもの（運転免許証、マイナンバーカード等）が必要とされています。詳細は公式で確認してください。', TRUE, '港区 保健福祉支援部 高齢者支援課 在宅支援係', '03-3578-2111', 'https://www.city.minato.tokyo.jp/zaitakushien/kenko/fukushi/koresha/sekatsu/kamiomutsu.html', 'https://www.city.minato.tokyo.jp/zaitakushien/kenko/fukushi/koresha/sekatsu/kamiomutsu.html', '港区ホームページ／高齢者紙おむつの給付', '2026-06-24', 'high', ARRAY['benefitAmountText', 'requiredDocumentsText', 'applicationDeadlineText', '所得制限の有無', '要介護度の詳細区分', '支給量・点数']::text[], '本情報は港区公式ページ（確認日2026-06-24）に基づく概要です。対象要件・支給内容・自己負担額・申請方法は変更される場合があり、また個別の支給可否は審査によります。最新かつ正確な内容は必ず港区の公式案内または高齢者支援課でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
