insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot elderly-diapers import', '{"slug":"tokyo-minato-elderly-diapers","status":"published","title":"高齢者紙おむつの給付（港区）","officialUrl":"https://www.city.minato.tokyo.jp/zaitakushien/kenko/fukushi/koresha/sekatsu/kamiomutsu.html","topic":"elderly-diapers"}'::jsonb, 'pilot:tokyo-minato-elderly-diapers:dG9reW8tbWluYXRvLWVsZGVybHktZGlhcGVyc3zp' from public.support_programs sp where sp.slug='tokyo-minato-elderly-diapers' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'shinjuku'), 'tokyo-shinjuku-elderly-diapers', '新宿区 おむつ費用助成（高齢者・要介護者向け）', '新宿区が、日常的におむつを必要とする在宅の高齢者・要介護者等に対して、おむつ費用を助成する区独自の制度です。現物による助成（現物助成）と、購入したおむつ代を助成する代金助成の2種類があります。助成限度額は令和6年1月利用分から月額10,000円で、利用者は限度額の範囲内でかかった費用の概ね1割を負担します（住民税非課税・生活保護受給等の方は負担が生じない取扱いとされています）。対象や金額の詳細は変更される場合があるため、必ず新宿区公式ページおよび高齢者支援課でご確認ください。', '新宿区にお住まいで、ふだんから紙おむつが必要な高齢者・要介護の方に、区がおむつ代を助成する制度です。おむつそのものを届けてもらう方法と、買ったおむつ代を助成してもらう方法があります。助成の上限は月10,000円で、多くの場合は費用の1割ほどの自己負担です（住民税非課税などの方は自己負担なしとされています）。対象になるかや金額の詳しい条件は、区の公式ページや高齢者支援課で確認してください。', 'subsidy', '新宿区に住所登録（住民票）があり、日常的におむつを必要とする方で、要介護1以上の方（介護保険第2号被保険者を含む）または65歳以上で医療機関に入院中の方が対象となります。あわせて介護保険料段階が第1〜8段階であること、心身障害者おむつ費用助成を受けていないことなどの要件が公式で示されています（特別養護老人ホーム等の入所者は対象外）。なお重度の心身障害者の方には別枠で『心身障害者おむつ費用助成』（身体障害者手帳1〜2級または愛の手帳1〜2度など、問い合わせは障害者福祉課）があるとされており、いずれも詳細は公式での確認が必要です。', '助成限度額は令和6年（2024年）1月利用分から月額10,000円（令和5年12月利用分までは月額7,000円）。利用者負担は助成限度額の範囲内でかかったおむつ費用の概ね1割。住民税非課税・生活保護受給等の方は自己負担が生じない取扱いとされています（公式で確認）。金額・負担割合は変更される場合があるため公式でご確認ください。', '公式ページに明確な通年の申請期限の記載は確認できませんでした。利用開始の時期や遡及の取扱いがある可能性があるため、申請時期は高齢者支援課にご確認ください。', '高齢者支援課（区役所本庁舎2階）または各高齢者総合相談センターの窓口で申請します。助成方法は現物助成（業者からの配送）または代金助成（領収書等の提出）から選びます。申請書のほか、状況に応じて確認書・口座振替依頼書等の提出が必要とされています。詳細・最新の手続きは新宿区公式ページまたは高齢者支援課でご確認ください。', '申請書、確認書、口座振替依頼書など（個別の状況により異なるとされています）。詳細は窓口・公式ページでご確認ください。', FALSE, '新宿区福祉部 高齢者支援課 高齢者支援係', '03-5273-4305', 'https://www.city.shinjuku.lg.jp/fukushi/file05_02_00006.html', 'https://www.city.shinjuku.lg.jp/fukushi/file05_02_00006.html', 'おむつ費用助成 - 新宿区', '2026-06-24', 'high', ARRAY['benefitAmountText', 'targetPeople', 'applicationDeadlineText', 'requiredDocumentsText']::text[], '本情報は新宿区公式サイト（最終更新2026-04-01）を確認して作成した概要です。対象要件・助成限度額・自己負担割合・必要書類等は変更される場合があり、個々の受給可否は区の審査により決定されます。申請前に必ず新宿区公式ページおよび高齢者支援課でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
