insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'bunkyo'), 'tokyo-bunkyo-elderly-diapers', '高齢者紙おむつ現物支給事業（文京区）', '文京区が、在宅で常時おむつを使用している要介護の高齢者等に対し、紙おむつを現物で支給（毎月配送）する制度です。介護保険で原則要介護3以上に認定された方などが対象とされており、利用者負担として月額の自己負担が設けられています（詳細・最新の条件は公式で確認してください）。', '文京区では、ねたきりなどで常にむつ（紙おむつ）が必要な在宅の高齢者に、紙おむつそのものを毎月とどけてくれる制度があります。介護保険で要介護3以上と認定された方などが対象とされ、利用には月500円ほどの自己負担があります（生活保護の世帯は無料）。申請は高齢福祉課や地域の高齢者あんしん相談センターの窓口、郵送でできます。対象になるかどうかや最新の金額は、必ず区の窓口や公式ページでご確認ください。', 'service', '文京区に住む高齢者で、失禁等により常時おむつを使用している在宅の要介護者などが対象となる可能性があります。公式案内では「介護保険で原則要介護3以上に認定され、常時おむつを使用している方」「紙おむつの持込ができる病院に医療保険により入院し常時おむつを使用している満65歳以上の方」とされ、令和7年4月1日からは40歳以上で医師の意見書を提出した方も対象に拡大したと案内されています。特別養護老人ホーム等の施設入所者は対象外とされる場合があるため、ご自身が対象となるかは公式・窓口でご確認ください。', '現物支給（紙おむつそのものの支給）。公式案内では、31種類の紙おむつの中から月45点（下限20点）まで組み合わせて選び、月に一度指定の場所へ配送するとされています。自己負担は月額500円（生活保護世帯は免除）、45点を超えた分は1点につき100円とされています。金額・点数は改定され得るため最新は公式でご確認ください。', '随時受付とみられます（明確な締切の記載は確認の範囲では見当たりません）。最新は公式でご確認ください。', '高齢福祉課の窓口、またはお近くの高齢者あんしん相談センター（地域包括支援センター）で申請するほか、郵送による申請も可能とされています。詳細な手続きは公式ページ・問い合わせ先でご確認ください。', '公式案内では、介護保険被保険者証またはマイナンバーカード等の本人確認書類、支給対象者の認めの印鑑が必要とされ、要介護2以下の場合は医師の意見書の提出が求められるとされています。必要書類は変わり得るため公式・窓口でご確認ください。', FALSE, '文京区 福祉部高齢福祉課 高齢福祉推進係', '03-5803-1213', 'https://www.city.bunkyo.lg.jp/b017/p003184.html', 'https://www.city.bunkyo.lg.jp/b017/p003184.html', '高齢者紙おむつ現物支給事業 | 文京区', '2026-06-24', 'high', ARRAY['benefitAmountText', 'targetPeople', 'applicationDeadlineText', 'requiredDocumentsText']::text[], '本内容は文京区公式ページ（最終更新2026年3月16日）を基にした概要です。対象条件・金額・支給内容・自己負担は変更される場合があるため、申請前に必ず文京区高齢福祉課（03-5803-1213）または公式ページで最新情報をご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
