insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot elderly-diapers import', '{"slug":"tokyo-bunkyo-elderly-diapers","status":"published","title":"高齢者紙おむつ現物支給事業（文京区）","officialUrl":"https://www.city.bunkyo.lg.jp/b017/p003184.html","topic":"elderly-diapers"}'::jsonb, 'pilot:tokyo-bunkyo-elderly-diapers:dG9reW8tYnVua3lvLWVsZGVybHktZGlhcGVyc3zp' from public.support_programs sp where sp.slug='tokyo-bunkyo-elderly-diapers' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'taito'), 'tokyo-taito-elderly-diapers', '紙おむつの支給（台東区）', '台東区が在宅等で常時紙おむつ等を使用する高齢者・要介護者を対象に行う区独自の支援制度。介護保険で要支援1以上の認定を受けた方、または65歳以上で病院に入院している方が対象となる可能性があります（区内に住所が必要）。支援は「現物の配送」「購入補助券」「おむつ代の助成」から月ごとに1種類を選ぶ形で、要支援・要介護度に応じて月3,000円〜7,000円相当とされています。住民税非課税世帯は自己負担が免除される旨が公式で案内されています。金額・対象区分の詳細は変更されることがあるため、必ず公式ページと窓口でご確認ください。', '在宅などで常時紙おむつを使う高齢者・要介護者向けに、台東区が紙おむつの現物配送・購入補助券・おむつ代助成のいずれかを行う制度です。介護保険の要支援1以上の認定がある方、または65歳以上で入院中の方などが対象になる可能性があります。住民税非課税世帯は自己負担が免除されます。申請は介護保険被保険者証を持って高齢福祉課か地域包括支援センターへ。金額や対象は変わることがあるので公式で確認してください。', 'service', '常時紙おむつ等を使用しており、介護保険で要支援1以上の認定を受けた方、または65歳以上で病院に入院している方が対象となる可能性があります（台東区内に住所が必要）。詳しい要件は公式でご確認ください。', '要支援1・2は月3,000円相当、要介護1・2は月5,000円相当、要介護3〜5は月7,000円相当と公式で案内されています（金額は変更される場合があるため公式でご確認ください）。', NULL, '受給者の介護保険被保険者証を持参のうえ、高齢福祉課またはお近くの地域包括支援センターで申請します。詳細は公式でご確認ください。', '受給者の介護保険被保険者証。その他の書類が必要な場合があるため、申請前に公式または窓口でご確認ください。', FALSE, '台東区 高齢福祉課 総合相談・給付担当', '03-5246-1224', NULL, 'https://www.city.taito.lg.jp/kenkohukusi/korei/serviceannai/kyuuhujosei/kamiomutu.html', '紙おむつの支給 - 台東区', '2026-06-24', 'high', ARRAY['所得制限の詳細区分', '入院・施設入所時の取扱い詳細']::text[], '本情報は公式サイトをもとにした概要です。対象・金額・申請方法は変更される場合があり、個別の受給可否を保証するものではありません。必ず台東区の公式ページおよび高齢福祉課にご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
