insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot elderly-diapers import', '{"slug":"tokyo-taito-elderly-diapers","status":"published","title":"紙おむつの支給（台東区）","officialUrl":"https://www.city.taito.lg.jp/kenkohukusi/korei/serviceannai/kyuuhujosei/kamiomutu.html","topic":"elderly-diapers"}'::jsonb, 'pilot:tokyo-taito-elderly-diapers:dG9reW8tdGFpdG8tZWxkZXJseS1kaWFwZXJzfOe0' from public.support_programs sp where sp.slug='tokyo-taito-elderly-diapers' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'sumida'), 'tokyo-sumida-elderly-diapers', '高齢者等紙おむつ等支給事業（墨田区）', '墨田区が、在宅または入院中で常時失禁状態にあり介助を要する高齢者・要介護者を対象に、紙おむつ等を現物支給する制度です。65歳以上の方、または要介護認定を受けている40歳〜64歳の方が対象で、要介護3以上の方、要介護2以下でも寝たきりや認知機能低下により常時失禁状態にある方（要介護2以下は申請前に相談が必要）、入院中で常時失禁状態にある方が対象となります。テープ型・パンツ型・尿取りパッド・フラット型のカタログから上限7,000ポイントまで選択して月1回配送されます。所得等により自己負担金がない場合があります。入院中で病院が紙おむつ持込不可の場合は、月額上限7,000円までの現金助成が受けられる場合があります。対象要件・自己負担額・支給上限の最新の詳細は墨田区の公式ページでご確認ください。', '墨田区にお住まいで、寝たきりや認知症などにより常におむつが必要な高齢者の方などに、区が紙おむつを届けてくれる制度です。種類を選んで月に1回届きます。自己負担は月400円または600円ですが、収入に応じて自己負担がない場合もあります。入院中の方には、病院に持ち込めない場合におむつ代の助成（月7,000円まで）が受けられる場合があります。詳しくは墨田区の公式ページや窓口でご確認ください。', 'service', '墨田区内に住む65歳以上の方、または要介護認定を受けている40歳〜64歳の方で、紙おむつを必要としている方が対象です。具体的には、要介護3以上の方、要介護2以下でも寝たきりや認知機能低下等により常時失禁状態にあり介助を要する方（要介護2以下は申請前に相談が必要）、または入院中で常時失禁状態にある方が対象となります。対象要件の詳細は公式でご確認ください。', 'テープ型・パンツ型・尿取りパッド・フラット型等から選択し、上限7,000ポイントまでの選択制で月1回配送される現物支給です。自己負担は月額400円または600円です（令和7年8月1日以降。それ以前は月額500円または700円でした）。所得等により自己負担金がない場合があります。入院中で病院が紙おむつ持込不可の場合は、月額上限7,000円までの現金助成があります。最新額は公式でご確認ください。', '申請書を提出した月が支給対象月となるとされています。毎月の注文・変更・配送中止等には締切日があるため、詳細は配送カタログや公式でご確認ください。', '申請書を墨田区の高齢者福祉課または高齢者支援総合センターへ提出します。', '申請書（高齢者の紙おむつ等支給申請書）が必要です。要介護度や本人確認に関する書類など、その他の必要書類は公式ページまたは窓口でご確認ください。', FALSE, '墨田区 高齢者福祉課 支援係', '03-5608-6168', 'https://www.city.sumida.lg.jp/kenko_fukushi/koureisya_kaigohoken/netakiri_nintisyou/omutu.html', 'https://www.city.sumida.lg.jp/kenko_fukushi/koureisya_kaigohoken/netakiri_nintisyou/omutu.html', '紙おむつをお届けします - 墨田区', '2026-06-24', 'high', ARRAY['income_limit', 'supply_point_limit', 'requiredDocumentsText', 'applicationDeadlineText']::text[], '対象要件・自己負担額・支給上限などは変更される場合があります。実際に受けられるかどうかは審査によります。必ず墨田区の公式ページまたは窓口で最新情報をご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
