insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'koto'), 'tokyo-koto-elderly-diapers', '高齢者紙おむつ支給及びおむつ購入費助成（江東区）', '江東区にお住まいの65歳以上で、要介護3〜5の認定や常時失禁状態など一定の要件に該当する方を対象に、紙おむつの現物支給、または入院等で持ち込めない場合のおむつ購入費助成（月額上限あり）を行う区の制度です。対象や金額の詳細は江東区公式でご確認ください。', '江東区では、65歳以上で要介護3〜5の認定を受けている方などに、紙おむつを毎月自宅へ届ける現物支給を行っています。入院などでおむつを持ち込めない場合は、購入費を助成する仕組み（月額の上限あり）もあります。対象になるかどうかは区役所の介護保険課でご相談ください。', 'service', '江東区在住で65歳以上、要介護3・4・5の認定を受けている方、または医師の診断書により常時失禁状態と認められる方などが対象となる可能性があります。介護保険料段階が第1〜第8段階で、施設入所しておらず生活保護を受給していないことなどの要件があります。要介護2以下でも重度の認知症等で常時失禁状態の場合は診断書提出により対象となる可能性があります。具体的な対象要件は江東区公式でご確認ください。', '紙おむつの現物支給（毎月1回自宅等へ配送、支給限度75点の範囲内で選択）と、入院中などでおむつを持ち込めない場合のおむつ購入費助成（公式記載では月額7,500円を上限）があります。金額・支給量は変更される可能性があるため公式でご確認ください。', '申請受理月以降が助成対象で、さかのぼっての支給はできないとされています（随時申請）。詳細は公式でご確認ください。', '江東区役所の福祉部介護保険課在宅支援係（区役所3階4番）の窓口で申請します。現物支給は高齢者紙おむつ支給申請書・紙おむつ注文票（転入者は所得証明書）、購入費助成は高齢者おむつ購入費助成申請書・口座振替依頼書が必要とされています。申請受理月以降が対象で、さかのぼっての支給はできないとされています。詳細・最新の手続きは公式でご確認ください。', '現物支給：高齢者紙おむつ支給申請書、紙おむつ注文票、（転入者は）所得証明書。購入費助成：高齢者おむつ購入費助成申請書、口座振替依頼書。必要書類は変更される可能性があるため公式でご確認ください。', FALSE, '江東区 福祉部 介護保険課 在宅支援係', '03-3647-4319', 'https://www.city.koto.lg.jp/212106/fukushi/koresha/service/jisshi/6590.html', 'https://www.city.koto.lg.jp/212106/fukushi/koresha/service/jisshi/6590.html', '高齢者紙おむつ支給及びおむつ購入費助成 - 江東区', '2026-06-24', 'high', ARRAY['benefitAmountText', 'requiredDocumentsText', 'applicationDeadlineText', 'targetPeople']::text[], '本情報は江東区公式サイトの制度ページ（2026-06-24確認）に基づく概要です。対象要件・金額・支給量・申請方法は変更される場合があるため、申請前に必ず江東区公式または窓口でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
