insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot elderly-diapers import', '{"slug":"tokyo-koto-elderly-diapers","status":"published","title":"高齢者紙おむつ支給及びおむつ購入費助成（江東区）","officialUrl":"https://www.city.koto.lg.jp/212106/fukushi/koresha/service/jisshi/6590.html","topic":"elderly-diapers"}'::jsonb, 'pilot:tokyo-koto-elderly-diapers:dG9reW8ta290by1lbGRlcmx5LWRpYXBlcnN86auY' from public.support_programs sp where sp.slug='tokyo-koto-elderly-diapers' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'shinagawa'), 'tokyo-shinagawa-elderly-diapers', '紙おむつなどの支給（品川区）', '品川区の制度として、在宅で常時おむつが必要な区民に紙おむつや尿とりパッドを毎月1回宅配する事業です。運営は品川区社会福祉協議会が担い、要介護認定を受けた在宅高齢者や、一定の障害者手帳所持者などが対象とされています。公式の制度ページは障害のある方向けの案内で、高齢者・要介護を含む対象全体の詳細は品川区社会福祉協議会の案内によります。対象・条件は必ず公式および同協議会でご確認ください。', '品川区で在宅生活をしていて常時おむつが必要な高齢者・要介護の方や、一定の障害のある方に、紙おむつや尿とりパッドを月1回宅配で届ける品川区の事業です（運営は品川区社会福祉協議会）。要介護度や障害者手帳の有無などの条件があり、対象になるかは公式・社会福祉協議会への確認が必要です。', 'service', '在宅で常時おむつが必要な品川区民が対象となる可能性があります。公式の制度ページ（障害のある方への案内）では『身体障害者手帳・愛の手帳所持者で常時失禁のある方（その他支給要件あり）』とされています。加えて、品川区社会福祉協議会の案内によると、要介護3・4・5の在宅高齢者、要介護1・2で紙おむつが必要かつ民生委員の確認がある方、下肢・体幹機能障害の身体障害者手帳所持者、愛の手帳所持者（3歳以上）なども対象とされ、要支援者・生活保護受給中の方・施設入所者・長期入院中の方・日常生活用具として給付を受けている方は対象外とされています。高齢者・要介護に関する条件は社会福祉協議会の案内に基づく情報であり、対象に該当するかは必ず公式・品川区社会福祉協議会でご確認ください。', 'おむつカバー型・パンツ型の紙おむつ、または尿とりパッドを毎月1回、指定の住所へ宅配（現物支給）。1か月あたりの支給量や限度額は公式に明記がなく、公式・品川区社会福祉協議会での確認が必要です。', '毎月5日（5日が土日・祝日の場合は前営業日）までの受付分が当月の宅配対象とされています（社会福祉協議会の案内による）。詳細は公式でご確認ください。', '申請窓口は品川区社会福祉協議会です。申請時に介護保険証または障害者手帳を持参するよう案内されています。要介護1・2の方は、まずお近くの民生委員へ相談するよう案内されています。毎月5日（5日が土日・祝日の場合は前営業日）までの受付分が当月の宅配対象とされ、おおむね毎月16日から22日の間に順次配送されるとされています（社会福祉協議会の案内による）。最新の手続きは公式・社会福祉協議会でご確認ください。', '介護保険証または障害者手帳（品川区社会福祉協議会の案内による。詳細・その他の支給要件は公式・同協議会で要確認）', FALSE, '社会福祉法人品川区社会福祉協議会', '03-5718-7171', 'https://shinashakyo.jp/about/service/omutsu.html', 'https://www.city.shinagawa.tokyo.jp/PC/kenkou/kenkou-syogai/kenkou-syogai-nichizyouenzyo/kenkou-syogai-nichizyouenzyo-sonota/hpg000000596.html', '紙おむつなどの支給｜品川区', '2026-06-24', 'medium', ARRAY['benefitAmountText', 'requiredDocumentsText', '所得制限の有無', '月の支給量・限度額', '要介護度ごとの詳細条件', '障害種別ごとの詳細条件', '公式city.shinagawa.tokyo.jp上での高齢者・要介護向けの根拠ページ（officialUrlは障害者向けページのみで高齢者・要介護の記載なし。高齢者・要介護条件は社協ページが唯一の出典）', '公式ページが2019年更新のため最新性']::text[], '本ページは公式情報および品川区社会福祉協議会の案内をもとにした概要です。公式の制度ページは障害のある方向けの案内で（更新日：令和元年10月1日）、高齢者・要介護を含む対象全体や支給量・所得条件・申請方法の詳細は変更される場合があり、個別の該当可否は審査によります。必ず品川区公式ページおよび品川区社会福祉協議会の最新情報をご確認のうえ、ご相談ください。', 'review', NULL, now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
