insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot elderly-diapers import', '{"slug":"tokyo-shinagawa-elderly-diapers","status":"review","title":"紙おむつなどの支給（品川区）","officialUrl":"https://www.city.shinagawa.tokyo.jp/PC/kenkou/kenkou-syogai/kenkou-syogai-nichizyouenzyo/kenkou-syogai-nichizyouenzyo-sonota/hpg000000596.html","topic":"elderly-diapers"}'::jsonb, 'pilot:tokyo-shinagawa-elderly-diapers:dG9reW8tc2hpbmFnYXdhLWVsZGVybHktZGlhcGVy' from public.support_programs sp where sp.slug='tokyo-shinagawa-elderly-diapers' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'meguro'), 'tokyo-meguro-elderly-diapers', '紙おむつ等の支給(目黒区)', '目黒区が、在宅で要介護状態にある高齢者などを対象に、紙おむつ等を現物で支給する区独自の制度です。公式によると、65歳以上で区内在住・現に失禁状態にあり要介護2〜5で在宅の方(または病院に入院中で区から支給する紙おむつを使用できる方)が対象となる可能性があります。カタログに記載のおむつ・尿取りパッド等から合計6,600円以内で選択したものを毎月1回支給し、注文金額に応じた自己負担が生じる場合があります。生活保護受給者や介護保険施設入所者は対象外とされています。詳細・最新の条件は必ず目黒区公式でご確認ください。', '目黒区が、在宅で介護が必要な高齢者などに紙おむつを毎月届けてくれる制度です。65歳以上・区内在住・要介護2〜5で在宅の方などが対象になる可能性があります。毎月6,600円分まで、カタログから選んだおむつを受け取れます。申請は高齢福祉課か地域包括支援センターで行います。条件や金額は変わることがあるので、必ず目黒区の公式ページで確認してください。', 'service', '65歳以上で目黒区内在住、現に失禁状態にあり、要介護2〜5で在宅の方が対象となる可能性があります。病院に入院中で区から支給する紙おむつを使用できる方も対象となる場合があります。一方、生活保護受給者や介護保険施設(特別養護老人ホーム・介護老人保健施設等)入所者は対象外とされています。対象の詳しい要件は公式でご確認ください。', 'カタログに記載のおむつ・尿取りパッド等から合計金額6,600円以内で選択したものを毎月1回支給(現物支給)。注文金額に応じて100〜600円程度の自己負担が生じる場合があります。金額・自己負担額は変更される可能性があるため公式でご確認ください。', '随時申請を受け付けています(配送時期は申請受理日により異なります)。詳細は公式でご確認ください。', '高齢福祉課または各地域包括支援センターで「高齢者紙おむつ支給申請書」を提出して申請します。毎月13日までに受理された場合は当月20〜25日、25日までに受理された場合は翌月1〜10日の間に配送される運用とされています。申請方法の詳細は公式でご確認ください。', '高齢者紙おむつ支給申請書。要介護1以下で入院中の場合は、別途「高齢者紙おむつ支給申請者入院証明書」(区所定の用紙)が必要となる場合があります。必要書類は状況により異なるため公式でご確認ください。', FALSE, '目黒区 高齢福祉課 在宅事業係', '03-5722-9839', 'https://www.city.meguro.tokyo.jp/koureifukushi/kenkoufukushi/koureisha/kamiomutsu.html', 'https://www.city.meguro.tokyo.jp/koureifukushi/kenkoufukushi/koureisha/kamiomutsu.html', '紙おむつ等の支給 | 目黒区', '2026-06-24', 'high', ARRAY['benefitAmountText', 'applicationDeadlineText', 'requiredDocumentsText']::text[], '本情報は目黒区公式ページ(2026-06-24確認)に基づく概要です。対象要件・金額・自己負担・支給量・申請方法は変更される場合があり、個別の受給可否は審査により決まります。最新かつ正確な情報は必ず目黒区の公式ページまたは高齢福祉課でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
