insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'ota'), 'tokyo-ota-elderly-diapers', '大田区 紙おむつ等の支給（要介護等高齢者紙おむつ等支給事業）', '大田区では、在宅で失禁のため紙おむつを必要とする要介護等の高齢者に対し、介護する家族の経済的・精神的負担の軽減を目的に紙おむつを現物支給しています。毎月一定の点数の範囲内でカタログから製品を選択でき、区が指定する病院以外に入院中の方には費用助成（現金支給）の取り扱いもあります。対象や支給内容の詳細は公式ページで確認できます。', '大田区では、在宅で寝たきりなどにより紙おむつが必要な要介護の高齢者に、紙おむつを届けてくれる制度があります。毎月決まった点数の範囲でカタログから選べます。区が指定する病院以外に入院していて区の紙おむつが使えない場合は、おむつ代の一部（月5,000円まで）を現金で助成してもらえる場合があります。申請は、65歳以上の方は地域包括支援センター、40～64歳の方は地域福祉課が窓口です。対象になるかどうかや金額は、必ず大田区の公式ページや窓口で確認してください。', 'service', '大田区内に住民登録があり現に居住し、失禁のため紙おむつを必要とする方のうち、要介護3～5の認定を受けた方、要介護1・2の認定を受け医師が紙おむつを必要と認めた方、または65歳以上で入院中でこれらに相当する状態にある方が対象とされています（対象になるかは個別審査。詳細は公式で要確認）。', '紙おむつの現物支給。毎月の支給限度点数（現行は500点）の範囲内でカタログから製品を選択・組み合わせでき、点数を超えた分は自己負担です。なお公式では「令和8年4月分の配送から各商品の点数および一部商品名が変更される」旨が告知されています。区が指定する病院以外に入院中の方には、月5,000円を限度とする費用助成（本人名義口座へ振込）の取り扱いもあります。点数・金額は改定される場合があるため、必ず公式で確認してください。', '毎月10日までの申請で当月分から、11日以降の申請で翌月分から支給開始とされています。入院中の方の費用助成の請求は年3回、3月・7月・11月の各20日までとされています（最新の期限は公式で確認してください）。', '申請窓口は、65歳以上の方はお住まいの地域を担当する地域包括支援センター、40～64歳の方は各地域福祉課の高齢者地域支援担当です。要介護1・2の方は医師記入の「紙おむつ使用証明書」が必要となります。毎月10日までの申請で当月分から、11日以降の申請で翌月分から支給が開始される運用とされています（詳細・最新の手続きは公式ページや窓口で確認してください）。', '要介護1・2の方は、医師が記入した「紙おむつ使用証明書」が必要です。入院中の方の費用助成を申請する際は、本人名義の口座がわかるもの（通帳等）と印鑑（朱肉を使用するもの）が必要とされています。必要書類は公式ページ・窓口で確認してください。', FALSE, '大田区 各地域福祉課 高齢者地域支援担当（お住まいの地域の地域包括支援センター）', '03-5764-0658（大森地域福祉課）', NULL, 'https://www.city.ota.tokyo.jp/seikatsu/fukushi/kourei/kyufu/kamiomutu.html', '大田区ホームページ：紙おむつ等の支給', '2026-06-24', 'high', ARRAY['benefitAmountText', 'applicationDeadlineText', 'requiredDocumentsText', 'targetPeople']::text[], '対象条件・支給点数・金額・申請期限などは変更される場合があります。本情報は確認日（2026-06-24）時点の大田区公式ページに基づく概要です。実際に対象となるか、支給を受けられるかは個別の審査により決まりますので、必ず大田区の公式ページまたは窓口でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
