insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot elderly-diapers import', '{"slug":"tokyo-ota-elderly-diapers","status":"published","title":"大田区 紙おむつ等の支給（要介護等高齢者紙おむつ等支給事業）","officialUrl":"https://www.city.ota.tokyo.jp/seikatsu/fukushi/kourei/kyufu/kamiomutu.html","topic":"elderly-diapers"}'::jsonb, 'pilot:tokyo-ota-elderly-diapers:dG9reW8tb3RhLWVsZGVybHktZGlhcGVyc3zlpKfn' from public.support_programs sp where sp.slug='tokyo-ota-elderly-diapers' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'setagaya'), 'tokyo-setagaya-elderly-diapers', '紙おむつの支給・おむつ代の助成（高齢者向け）', '世田谷区が、在宅でねたきり等・失禁状態にあり一定の要件を満たす高齢者等に対し、紙おむつを現物支給する制度です。要介護3〜5などの身体状態が要件とされ、月1回自宅へ配達されます。利用者負担は月500円（一定点数まで）で、入院中の場合はおむつ代助成（月額の限度あり）の対象となる場合があります。金額・点数・要件の細目は変更され得るため、公式ページで最新情報を確認してください。', '世田谷区では、在宅で寝たきりなどの状態にあり、おむつが必要な高齢者などに紙おむつを届ける制度があります。要介護3〜5などの条件があり、利用者の負担は月500円程度です。入院している場合は、おむつ代の助成を受けられる場合があります。まずはお住まいの地域の総合支所保健福祉課やあんしんすこやかセンターにご相談ください。', 'service', '世田谷区に住所があり、65歳以上または40〜64歳の介護保険第2号被保険者で要介護3〜5などに該当し、ねたきり等の状態が継続し失禁のため2か月以上おむつの使用が必要と認められ、介護保険施設に入所していない方が対象となる可能性があります。詳細な要件・対象範囲は公式で確認してください。', '現物支給では利用者負担金が月500円（40点分まで。超過分は1点につき100円、ダンボール梱包希望時は150円）とされています。入院中の場合は「おむつ代助成」として月額5,000円を限度に助成されるとされています。金額・点数は変更され得るため公式で確認してください。', '通年で随時申請を受け付けているとみられます。ただし申請した月以降が対象となり遡及申請は原則不可とされているため、詳細は公式・窓口で確認してください。', '住所地を管轄する各総合支所保健福祉課、またはあんしんすこやかセンターで利用申請を行います。申請した月以降からが支給・助成の対象とされ、遡及申請は原則できないとされています。詳細は公式ページおよび窓口で確認してください。', '必要書類は公式ページに明記されていません。申請窓口（各総合支所保健福祉課・あんしんすこやかセンター）で確認してください。', FALSE, '世田谷区 高齢福祉課', '03-5432-2407', NULL, 'https://www.city.setagaya.lg.jp/02082/2415.html', '紙おむつの支給・助成 | 世田谷区公式ホームページ', '2026-06-24', 'high', ARRAY['requiredDocumentsText', 'applicationDeadlineText']::text[], '対象要件・自己負担額・支給点数・助成限度額などは変更される場合があります。最新かつ正確な情報は世田谷区公式ページおよび申請窓口でご確認ください。本情報は申請による支給を保証するものではありません。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
