insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot elderly-diapers import', '{"slug":"tokyo-setagaya-elderly-diapers","status":"published","title":"紙おむつの支給・おむつ代の助成（高齢者向け）","officialUrl":"https://www.city.setagaya.lg.jp/02082/2415.html","topic":"elderly-diapers"}'::jsonb, 'pilot:tokyo-setagaya-elderly-diapers:dG9reW8tc2V0YWdheWEtZWxkZXJseS1kaWFwZXJz' from public.support_programs sp where sp.slug='tokyo-setagaya-elderly-diapers' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'shibuya'), 'tokyo-shibuya-elderly-diapers', '渋谷区 紙おむつ購入費助成', '渋谷区に住民票があり常時紙おむつを使用している在宅の高齢者・要介護者や障害のある方を対象に、渋谷区と渋谷区社会福祉協議会が紙おむつの購入費を助成する区独自の制度です。利用には事前の登録・申請が必要で、対象や助成額などの条件は公式で確認してください。', '渋谷区では、紙おむつを使っている在宅の高齢者・要介護の方や障害のある方に向けて、紙おむつの購入費を区と社会福祉協議会が助成しています。社協の案内では助成の限度額は月額3,500円とされ、登録すると毎月決まった日までの注文で翌月初めに自宅へ届く仕組みです。利用するには先に登録・申請が必要なので、対象になるかどうかや助成の金額は、区の窓口（地域支援事業課）や公式ページで確認してください。', 'subsidy', '渋谷区に住民票があり、常時紙おむつを使用している在宅の方で、生活保護を受けていない方が対象です。公式情報によると、(1)介護保険の要介護1以上の認定を受けた方、(2)3歳以上で身体障害者手帳・愛の手帳・精神障害者保健福祉手帳を持つ方、(3)3歳以上で障害者総合支援法に基づく難病等の対象となる方のいずれかが含まれます。特別養護老人ホーム・老人保健施設・介護医療院などの施設に入所している方は対象外とされています。具体的な対象条件は必ず渋谷区の公式情報で確認してください。', '渋谷区と渋谷区社会福祉協議会が紙おむつの購入費を助成します。渋谷区社会福祉協議会の公式案内では助成限度額を月額3,500円としています。一部の案内では商品価格の約2割の自己負担で購入できるとする記述もあり、自己負担割合や支給量などの運用は変わる可能性があるため、最新の金額・条件は必ず公式で確認してください。', '通年で申請を受け付けています（注文は毎月20日締めで翌月初旬の配達となる運用とされています）。詳細は公式で確認してください。', '事前の登録・申請が必要です。申請書に必要事項を記入し、介護保険被保険者証や各種障害者手帳（身体障害者手帳・愛の手帳・精神障害者保健福祉手帳）の写しを添えて申請します。難病等の方は意見書が必要とされています。登録後は毎月20日までに注文すると翌月初旬（1日〜7日頃）に月1回自宅へ配達される運用です。詳しい申請方法・必要書類は公式で確認してください。', '申請書のほか、介護保険被保険者証や各種障害者手帳（身体障害者手帳・愛の手帳・精神障害者保健福祉手帳）の写しが必要です。難病等の方は意見書が必要とされています。最新の必要書類は公式で確認してください。', FALSE, '渋谷区 地域支援事業課（地域福祉係）', '03-5457-2200', 'https://www.shibuyashakyo.or.jp/chk/kamiomutsu-o.html', 'https://www.city.shibuya.tokyo.jp/kenko/shogai-seikatsu/shien-kaigo-seikatsu/syakyo-service.html', '渋谷区社会福祉協議会のサービス（くらしの支援）｜渋谷区ポータル', '2026-06-24', 'high', ARRAY['自己負担割合', '要介護度別の支給量', '所得制限の有無', 'requiredDocumentstext']::text[], '本情報は確認日（2026-06-24）時点の公式情報に基づく概要です。助成限度額・自己負担割合・支給量・所得などの条件は変更される場合があり、情報源によって記載に差があります。最新かつ正確な内容は必ず渋谷区の公式情報・窓口でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
