insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot elderly-diapers import', '{"slug":"tokyo-shibuya-elderly-diapers","status":"published","title":"渋谷区 紙おむつ購入費助成","officialUrl":"https://www.city.shibuya.tokyo.jp/kenko/shogai-seikatsu/shien-kaigo-seikatsu/syakyo-service.html","topic":"elderly-diapers"}'::jsonb, 'pilot:tokyo-shibuya-elderly-diapers:dG9reW8tc2hpYnV5YS1lbGRlcmx5LWRpYXBlcnN8' from public.support_programs sp where sp.slug='tokyo-shibuya-elderly-diapers' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'nakano'), 'tokyo-nakano-elderly-diapers', '中野区 おむつサービス（紙おむつの支給）', '中野区が在宅で常時おむつを必要とする高齢者・障害者に紙おむつを現物支給する区独自の福祉サービス。65歳以上で要介護1〜5の認定を受け、世帯全員の前年合計所得が350万円未満の方などが対象となる可能性があります。詳細・最新の要件は中野区公式で確認してください。', '中野区では、在宅でいつもおむつが必要な高齢の方や障害のある方に、区が紙おむつを直接お届けするサービスがあります。65歳以上で介護が必要と認定され、世帯の所得が一定額未満などの条件に当てはまると利用できる可能性があります。まずはお住まいの地域の地域包括支援センター（高齢者の場合）にご相談ください。必ず利用できるとは限らず、対象かどうかは区の窓口での確認が必要です。', 'service', '在宅で常時おむつを必要とする方のうち、(1)65歳以上で介護保険の要介護1〜5の認定を受け、世帯全員の前年合計所得金額が350万円未満の高齢者、または(2)3歳以上で身体障害者手帳1〜2級・精神障害者保健福祉手帳1〜2級・愛の手帳1〜2度をお持ちの障害者が対象となる可能性があります。具体的な該当可否や所得・要介護度などの要件は中野区公式でご確認ください。', '紙おむつを現物支給。種類は4型（パンツ型・テープ型・尿とりパッド・フラット型）で、月60点の支給限度点数内で必要量を支給。金額や1か月あたりの支給量の上限は対象者の状況により異なる可能性があり、公式での確認が必要です。', '随時受付。毎月25日の締切日までに申請された分について、翌月から支給開始（公式記載）。詳細は窓口でご確認ください。', '高齢者は担当区域の地域包括支援センターで申請、障害者は障害福祉課（区役所3階5番窓口）で申請します。初回利用時は窓口での申請が必要となる可能性があります。詳細は中野区公式・各窓口でご確認ください。', '介護保険証（高齢者の場合）、または身体障害者手帳・精神障害者保健福祉手帳・愛の手帳のいずれか（障害者の場合）。写しでの提出も可。その他の必要書類は申請窓口でご確認ください。', FALSE, '中野区 地域支えあい推進部 地域包括ケア推進課 在宅サービス係', '03-3228-5632', 'https://www.city.tokyo-nakano.lg.jp/kenko_hukushi/kourei/hokenhukushi/omutsu.html', 'https://www.city.tokyo-nakano.lg.jp/kenko_hukushi/kourei/hokenhukushi/omutsu.html', 'おむつサービス（紙おむつの支給） | 中野区', '2026-06-24', 'high', ARRAY['benefitAmountText', 'requiredDocumentsText', '所得制限の詳細・基準年', '要介護度別の支給量', '支給限度点数(60点)の金額換算', '入院時の費用助成(別枠)の詳細']::text[], '本情報は中野区公式サイトの掲載内容（2026-06-24確認）にもとづく概要です。所得制限・要介護度・支給量・金額などの詳細要件は変更される場合があり、また個別の該当可否は区の審査によります。最新かつ正確な情報は中野区公式・各申請窓口でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
