insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot elderly-diapers import', '{"slug":"tokyo-nakano-elderly-diapers","status":"published","title":"中野区 おむつサービス（紙おむつの支給）","officialUrl":"https://www.city.tokyo-nakano.lg.jp/kenko_hukushi/kourei/hokenhukushi/omutsu.html","topic":"elderly-diapers"}'::jsonb, 'pilot:tokyo-nakano-elderly-diapers:dG9reW8tbmFrYW5vLWVsZGVybHktZGlhcGVyc3zk' from public.support_programs sp where sp.slug='tokyo-nakano-elderly-diapers' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'suginami'), 'tokyo-suginami-elderly-diapers', '杉並区 介護用品の支給等（紙おむつ等の現物支給・入院時のおむつ代助成）', '杉並区が在宅の高齢者・要介護者を対象に、紙おむつなどの介護用品を月額7,000円を上限に専用カタログから選んで現物支給する区の制度です。決定月の翌月から自宅等へ毎月配送されます。おむつを持ち込めない病院に入院した場合には、おむつ代金の一部助成も受けられる可能性があります。金額・対象などの詳細は公式ページで確認してください。', '杉並区では、在宅で常時おむつが必要な高齢者・要介護者に対し、紙おむつなどの介護用品を月7,000円分まで選んで自宅に届けてもらえる制度があります。要介護3以上の方、または要介護1・2で常時おむつが必要な方が対象となる可能性があります。申請は窓口・郵送・電子申請で行え、毎月25日が新規申請の締切です。おむつを持ち込めない病院に入院した場合のおむつ代助成もあります。対象や金額は変わることがあるので、公式ページで確認してください。', 'service', '杉並区内に住所があり、在宅で常時おむつが必要な高齢者・要介護者が対象となる可能性があります。公式案内では、要介護3以上でおむつが必要な方、または要介護1・2で常時おむつが必要な方（身体状況確認書が必要）が対象とされ、介護保険施設に入所している方は対象外とされています。最終的な対象可否は公式で確認してください。', '介護用品（紙おむつ等）を月額7,000円を上限に専用カタログから選んで現物支給。おむつを持ち込めない病院に入院した場合は、おむつ代金の一部助成あり。金額は変更される可能性があるため公式で確認してください。', '新規申請受付は毎月25日締切（25日が土日・祝日の場合は前開庁日が締切）。', '電子申請フォーム、郵送、または窓口で「介護用品支給等申請書（第1号様式）」を提出して申請します。要介護1・2の方は「身体状況確認書（第2号様式）」の添付が必要です。新規申請は毎月25日が締切（25日が土日祝の場合は前開庁日）とされ、申請から1〜2週間程度で結果が通知されます。詳細・最新の手続きは公式ページで確認してください。', '介護用品支給等申請書（第1号様式）。要介護1・2の方は身体状況確認書（第2号様式）も必要。詳細は公式ページで確認してください。', TRUE, '杉並区 保健福祉部 高齢者在宅支援課 管理係', '03-5307-0649', 'https://www.city.suginami.tokyo.jp/s039/1166.html', 'https://www.city.suginami.tokyo.jp/s039/1166.html', '介護用品の支給等｜杉並区公式ホームページ', '2026-06-24', 'high', ARRAY['benefitAmountText', 'targetPeople', 'applicationDeadlineText']::text[], '金額・対象要件（要介護度・所得など）・支給量は変更される場合があります。最新かつ正確な情報は杉並区公式ページや所管課で必ず確認してください。本制度とは別に、重度障害者向けの「おむつ支給」制度（障害者施策課所管）も杉並区にあります。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
