insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot elderly-diapers import', '{"slug":"tokyo-suginami-elderly-diapers","status":"published","title":"杉並区 介護用品の支給等（紙おむつ等の現物支給・入院時のおむつ代助成）","officialUrl":"https://www.city.suginami.tokyo.jp/s039/1166.html","topic":"elderly-diapers"}'::jsonb, 'pilot:tokyo-suginami-elderly-diapers:dG9reW8tc3VnaW5hbWktZWxkZXJseS1kaWFwZXJz' from public.support_programs sp where sp.slug='tokyo-suginami-elderly-diapers' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'toshima'), 'tokyo-toshima-elderly-diapers', '高齢者紙おむつ等支給（豊島区）', '豊島区が実施する、在宅で常時紙おむつ等が必要な高齢者向けの現物支給制度。要介護認定や所得段階などの要件を満たすと、カタログから選んだ紙おむつ等が月1回配布されます（上限は月80点＝8,000円相当分、令和7年9月分から引上げ。金額・要件は改定され得るため公式で確認が必要）。入院中の方向けには別途「高齢者おむつ購入費等助成」があり、同月内の併給はできません。', 'おうちで暮らしていて、いつも紙おむつが必要な高齢の方に、豊島区が紙おむつなどを月1回お届けする制度です。要介護の認定や収入などの条件があります。申し込みは高齢者総合相談センターで受け付けています。', 'service', '豊島区にお住まいで、常時紙おむつ等が必要な在宅の高齢者が対象となる可能性があります。公式情報では、要介護認定が要介護1以上、介護保険料所得段階が第1～5段階、生活保護を受けていないことなどが要件として案内されています。有料老人ホームやグループホームにお住まいの方も在宅扱いとして対象となる場合があります。実際に対象となるかは要件の確認が必要なため、必ず豊島区の公式ページや窓口でご確認ください。', '月1回、紙おむつ等を現物で配布。上限は1か月あたり80点（8,000円相当分）とされています（令和7年9月分から70点→80点に引上げ）。金額・上限は改定される可能性があるため、最新の内容は公式ページでご確認ください。', '公式ページに明確な締切の記載は確認できませんでした。随時申請を受け付けている可能性がありますが、詳細は窓口でご確認ください。', '「高齢者紙おむつ等支給申請書」を、お住まいの地域を担当する高齢者総合相談センターに提出して申請します。豊島区の案内ではインターネットによる電子申請も利用できるとされています。申請書の様式や手続きの詳細、必要書類は公式ページで確認してください。問い合わせ先は高齢者福祉課高齢者事業グループ（電話 03-4566-2432）です。', '高齢者紙おむつ等支給申請書（豊島区公式ページでPDF様式が提供されています）。その他の必要書類は公式でご確認ください。', TRUE, '豊島区 高齢者福祉課 高齢者事業グループ', '03-4566-2432', NULL, 'https://www.city.toshima.lg.jp/379/kenko/koresha/ippansesaku/1502171019.html', '高齢者紙おむつ等支給 - 豊島区', '2026-06-24', 'high', ARRAY['benefitAmountText', 'applicationDeadlineText', 'requiredDocumentsText', '所得段階の区分', '要介護度の要件', '支給上限（点数・金額）']::text[], '対象要件・支給上限・金額などは制度改定により変わる可能性があります。最終的な可否や詳細は必ず豊島区の公式ページ・窓口でご確認ください。本情報は受給を確約するものではありません。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
