insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'kita'), 'tokyo-kita-elderly-diapers', '要介護高齢者等紙おむつ支給（東京都北区）', '東京都北区が、在宅で常時おむつが必要な要介護高齢者等に対して紙おむつを現物支給する制度です。カタログから紙おむつを選べます。対象は北区在住で常時おむつを必要とする方のうち、要介護4・5（40歳以上）または要介護3（75歳以上）に該当する方で、施設入所者は対象外です。支給量・回数・所得要件などの細部は公式ページで確認してください。', '北区にお住まいで、常時紙おむつが必要な在宅の要介護高齢者に、区が紙おむつそのものを支給する制度です。カタログから選べます。お近くの高齢者あんしんセンターで申請でき、介護保険証または要介護認定結果通知が必要です。ご自身が対象となるかは公式ページや問い合わせ先でご確認ください。', 'service', '北区在住で常時おむつを必要とする在宅の要介護高齢者等。公式ページでは、要介護4・5の認定を受けた40歳以上の方、または要介護3の認定を受けた75歳以上の方が対象とされ、施設入所者は対象外です。詳細な対象要件は公式でご確認ください。', '紙おむつの現物支給（カタログから選択）。支給量・回数等の細部は公式ページに記載がないため要確認。', NULL, '介護保険の保険証または要介護認定結果通知を持参し、各高齢者あんしんセンター（地域包括支援センター）で申請します。おむつ支給申請書の提出が必要です。', '介護保険の保険証または要介護認定結果通知、おむつ支給申請書', FALSE, '北区 福祉部 高齢福祉課 高齢相談係', '03-3908-9083', NULL, 'https://www.city.kita.lg.jp/socialcare-health/elderly/1008607/1008614.html', '要介護高齢者等紙おむつ支給｜東京都北区', '2026-06-24', 'high', ARRAY['benefitAmountText', 'requiredDocumentsText', 'applicationDeadlineText']::text[], '対象要件・支給量・所得要件などの詳細は変更される場合があります。最新の情報は北区公式ページまたは高齢福祉課・高齢者あんしんセンターでご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
