insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot elderly-diapers import', '{"slug":"tokyo-kita-elderly-diapers","status":"published","title":"要介護高齢者等紙おむつ支給（東京都北区）","officialUrl":"https://www.city.kita.lg.jp/socialcare-health/elderly/1008607/1008614.html","topic":"elderly-diapers"}'::jsonb, 'pilot:tokyo-kita-elderly-diapers:dG9reW8ta2l0YS1lbGRlcmx5LWRpYXBlcnN86KaB' from public.support_programs sp where sp.slug='tokyo-kita-elderly-diapers' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'arakawa'), 'tokyo-arakawa-elderly-diapers', '荒川区 高齢者紙おむつ購入費助成', '荒川区では、寝たきりや認知症等で在宅で紙おむつを必要とする高齢者等に対し、紙おむつの購入費（購入券または現物代の助成）を支給する制度を設けています。対象や金額の詳細は公式で確認してください。', '荒川区にお住まいで、寝たきりや認知症などのために紙おむつが必要な在宅の高齢者の方などを対象に、区が紙おむつの購入費を購入券などで助成する制度です。住民税が課税か非課税かによって助成額が変わります。対象や金額は最新の情報を区の公式ページや高齢者福祉課でご確認ください。', 'subsidy', '荒川区在住で、寝たきり又は認知症等により紙おむつを必要とする高齢者等が対象です。公式情報では、65歳以上または40〜64歳の介護保険第2号被保険者で、要介護4・5、要介護1〜3かつ認知症、身体障害者手帳1〜2級、愛の手帳1〜2度等のいずれかに該当する方が対象とされています（介護保険施設入所者・生活保護受給者は対象外）。要件の詳細は公式で確認してください。', '公式情報では、住民税非課税者は1か月7,800円分（2,600円券3枚）、課税者は1か月3,900円分（1,300円券3枚）の購入券が支給され、購入券利用時は10％分の自己負担があるとされています。金額・区分は年度により変わる可能性があるため公式で確認してください。', '区役所開庁時間内に随時受付とされています。最新の取扱いは公式で確認してください。', '高齢者福祉課（区役所2階）に「高齢者在宅保健福祉サービス利用申請書・同意書」を提出して申請するとされています。詳細・必要書類は公式でご確認ください。', '高齢者在宅保健福祉サービス利用申請書・同意書が必要とされています。詳細は公式でご確認ください。', FALSE, '荒川区 福祉部高齢者福祉課', '03-3802-3111（内線2661）', NULL, 'https://www.city.arakawa.tokyo.jp/a028/koureishairyou/shien/hokenfukushi.html', '高齢者の保健・福祉サービス／荒川区公式サイト', '2026-06-24', 'high', ARRAY['benefitAmountText', 'targetPeople']::text[], '本情報は荒川区公式サイトの記載に基づく概要です。対象要件・助成額・自己負担・支給量・申請方法は年度改定や個別の状況により異なる場合があり、受給を確約するものではありません。必ず最新の公式情報または高齢者福祉課にご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
