insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'itabashi'), 'tokyo-itabashi-elderly-diapers', '高齢者紙おむつ等の支給（板橋区）', '板橋区が、在宅の要介護高齢者等で常時失禁状態の方を対象に、紙おむつ等を現物支給（委託事業者による無料配送）する制度です。紙おむつの持ち込みを禁止している病院・施設に入院（入所）中の方には、おむつ代の一部を現金助成します。同一の月に現物支給と現金助成の両方を受けることはできません。対象要件や支給上限など詳細は板橋区の公式ページで確認してください。', '板橋区では、在宅で介護が必要で常に失禁状態の高齢者の方に、紙おむつを無料で配送してもらえる制度があります。紙おむつの持ち込みができない病院や施設に入院・入所している場合は、おむつ代の一部が現金で助成されます。所得などの条件があるので、利用できるか公式ページや区の窓口で確認してください。', 'service', '板橋区に住民登録があり、要介護1以上（40〜64歳で要介護認定を受けている方を含む）で常時失禁状態の在宅の高齢者等が対象となる可能性があります。所得制限があり、介護保険施設（特別養護老人ホーム・介護老人保健施設・介護医療院）に入所している方、生活保護世帯、板橋区心身障がい者紙おむつ助成を受けている方などは対象外とされています。具体的な対象要件は公式ページで確認してください。', '在宅の方は現物支給で、区の支給品の中から希望する商品を一定点数の範囲内で選んで注文できます。入院・入所中で紙おむつ持込禁止の場合は、おむつ代の一部が現金助成の対象となります。具体的な支給点数・助成上限額は変更される場合があるため、必ず板橋区公式ページで確認してください。', '', '窓口・郵送・電子申請（令和7年4月1日受付開始）で申請します。窓口・郵送先は健康生きがい部 高齢政策課ほか（〒173-8501 板橋区板橋2-66-1）。詳細・最新の手続きは板橋区公式ページで確認してください。', '', TRUE, '板橋区 健康生きがい部 高齢政策課 高齢者相談・給付係', '03-3579-2464', 'https://www.city.itabashi.tokyo.jp/kenko/kourei/josei/1044737/index.html', 'https://www.city.itabashi.tokyo.jp/kenko/kourei/josei/1044737/index.html', '高齢者紙おむつ等の支給｜板橋区公式ホームページ', '2026-06-24', 'high', ARRAY['benefitAmountText', 'targetPeople', 'requiredDocumentsText', 'applicationDeadlineText']::text[], '支給点数・助成上限額・所得基準などは改定されることがあります。最新の内容は必ず板橋区の公式ページまたは高齢政策課でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
