insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot elderly-diapers import', '{"slug":"tokyo-itabashi-elderly-diapers","status":"published","title":"高齢者紙おむつ等の支給（板橋区）","officialUrl":"https://www.city.itabashi.tokyo.jp/kenko/kourei/josei/1044737/index.html","topic":"elderly-diapers"}'::jsonb, 'pilot:tokyo-itabashi-elderly-diapers:dG9reW8taXRhYmFzaGktZWxkZXJseS1kaWFwZXJz' from public.support_programs sp where sp.slug='tokyo-itabashi-elderly-diapers' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'nerima'), 'tokyo-nerima-elderly-diapers', '高齢者等紙おむつ等支給事業（練馬区）', '練馬区が、常時紙おむつを必要とする在宅の高齢者・要介護者に対し、区指定の紙おむつ製品から希望するものを毎月1回配達する現物支給の制度です。利用者負担は注文額の約1割（一定額超過分は別計算）。入院で紙おむつを持ち込めない場合は、おむつ代として月額上限5,400円を支給する仕組みも併設されています。対象や負担額には要介護度・所得段階などの条件があるため、適用可否は練馬区公式・窓口でご確認ください。', 'ねりま区が、いつも紙おむつが必要な在宅の高齢の方・介護が必要な方に、区が選んだ紙おむつを毎月1回届けるしくみです。利用する人のお金の負担は、注文した金額のだいたい1割です。入院で紙おむつを持ち込めないときは、おむつ代として月5,400円までを支給します。対象になるかどうかは、要介護度や所得などの条件があるので、区の公式ページや窓口で確認してください。', 'service', '練馬区の介護保険被保険者で、要介護1以上（40〜64歳で認定を受けている方を含む）と認定され、常時紙おむつを必要とする方が対象となる可能性があります。介護保険料所得段階が第8段階以下（前年合計所得320万円以下の目安）であることなどの所得要件があり、生活保護受給者・施設入所者・他制度で支給を受けている方などは対象外とされています。要介護1〜3の方は、認定調査で排尿・排便に介助や見守りが必要と判定されていることが要件とされる場合があります。詳細な要件は練馬区公式でご確認ください。', '在宅の場合は現物支給で、利用者負担は注文した紙おむつの総額の約1割。注文額が6,000円までは1割負担、6,001円以上の場合は注文金額から5,400円を差し引いた額が利用者負担となります（公式で確認）。入院等で紙おむつを持ち込めない場合は、おむつ代として月額上限5,400円が支給されます。金額・支給量は条件により変わるため公式でご確認ください。', NULL, 'お近くの総合福祉事務所の高齢者支援係の窓口で申請するか、練馬区の電子申請フォームから申し込みます。申請時には介護保険の保険証が必要で、施設退所者は退所証明書、転入者は住民税課税（非課税）証明書などが求められる場合があります。', '介護保険の保険証。施設退所者は退所証明書、転入者は住民税課税（非課税）証明書が必要となる場合があります（公式で確認）。', TRUE, '練馬区 高齢者支援課 高齢給付係', '03-5984-2774', 'https://www.city.nerima.tokyo.jp/hokenfukushi/koreisha/nichijo/kamiomutsu.html', 'https://www.city.nerima.tokyo.jp/hokenfukushi/koreisha/nichijo/kamiomutsu.html', '高齢者等の紙おむつなどの支給：練馬区公式ホームページ', '2026-06-24', 'high', ARRAY['benefitAmountText', 'targetPeople', 'requiredDocumentsText']::text[], '本内容は練馬区公式ページ（確認日2026-06-24）に基づく概要です。対象要件・利用者負担額・支給量などは変更される場合があり、個別の適用可否は練馬区の公式情報および総合福祉事務所の窓口で必ずご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
