insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'adachi'), 'tokyo-adachi-elderly-diapers', '紙おむつの支給（高齢者用）', '足立区が、在宅で常時失禁状態のため紙おむつを必要とする要介護高齢者に対し、区のカタログから選んだ紙おむつを月1回自宅へ現物支給する制度。入院などで持ち込みができない場合は月額上限ありの費用助成も用意されている。対象・支給量・申請方法は公式で確認のこと。', '足立区では、在宅で介護を受けていて常におむつが必要な高齢の方に、区が選んだ紙おむつを毎月1回自宅へ届けてくれる制度があります。入院していておむつを持ち込めないときは、代わりにおむつ代の一部（月6,000円まで）を助成してもらえる場合もあります。申請は地域包括支援センターや区の窓口で行います。対象になるかどうかは要介護度などの条件があるため、まずは区の高齢福祉課に相談してみましょう。', 'service', '足立区に住民登録があり、介護保険の要介護認定が2・3・4・5で常時失禁状態のため紙おむつを必要とする在宅の方が対象となる可能性があります（公式で確認）。生活保護受給者・中国帰国者支援給付受給者・介護保険施設入所者は対象外とされています。所得制限の有無や対象となる要介護度の下限など、具体的な条件は変更される場合があるため必ず足立区高齢福祉課で最新情報をご確認ください。', '区のカタログから選んだ紙おむつを認定の翌月から月1回自宅へ現物支給。病院入院中などで紙おむつを持ち込めない場合は、月額6,000円を限度に費用を助成（公式で確認）。支給量・上限額・カタログ内容は変更される場合があります。', NULL, '地域包括支援センター、足立区高齢福祉課在宅支援係、または足立福祉事務所各課の総合相談窓口で申請します。申請書（高齢者用紙おむつ等支給申請書）の提出が必要です。詳しい手続き・必要書類は公式ページや窓口でご確認ください。', '高齢者用の紙おむつ等支給申請書の提出が必要とされています。本人確認書類や介護保険の認定状況がわかるものなど、その他の必要書類は足立区高齢福祉課でご確認ください。', FALSE, '足立区 高齢福祉課 在宅支援係', '03-3880-5257', 'https://www.city.adachi.tokyo.jp/k-fukushi/kaigohokengai.html', 'https://www.city.adachi.tokyo.jp/k-fukushi/kaigohokengai.html', '高齢者サービスのご案内（介護保険外高齢者サービス）｜足立区', '2026-06-24', 'high', ARRAY['benefitAmountText', 'targetPeople', 'requiredDocumentsText']::text[], '本ページは足立区公式サイトの情報をもとにまとめた参考情報です。対象要件・支給量・金額・申請方法は変更される場合があります。実際の利用可否や手続きは足立区高齢福祉課または地域包括支援センターで必ずご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
