insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'katsushika'), 'tokyo-katsushika-elderly-diapers', '葛飾区 おむつの支給・使用料の助成（紙おむつ支給事業）', '葛飾区が在宅の要介護高齢者・重度障害のある方を対象に、紙おむつを毎月自宅へ現物配送し、入院等で区支給のおむつを利用できない場合に紙おむつ代を助成する制度です。対象や支給量・助成額は要介護度や障害等級などにより異なり、住民税非課税などの要件があります。詳細は必ず葛飾区の公式案内でご確認ください。', '葛飾区では、家で介護を受けている高齢の方や、重い障害のある方で、いつも紙おむつが必要な方に、紙おむつを毎月自宅へ届けてくれる仕組みがあります。入院などで区の紙おむつが使えないときは、自分で買った紙おむつ代の一部を後からお金で助成してもらえる場合があります。対象になるかどうかや、もらえる量・金額には条件があるので、葛飾区の窓口（高齢者支援課 在宅サービス係 03-5654-8299）に相談してみてください。', 'service', '葛飾区内在住で常時おむつ（紙おむつ）を必要とする在宅の方が対象となる可能性があります。公式案内では、要介護認定を受けた高齢者（おおむね要介護2以上）や、65歳以上で身体障害者手帳1・2級・愛の手帳1・2度をお持ちの方、脳性まひ・進行性筋萎縮症の方などが対象として挙げられており、住民税非課税などの要件があります。ご自身が対象となるか・支給内容は、必ず葛飾区の公式窓口でご確認ください。', '現物支給は要介護度・障害等級に応じて1か月あたりの支給ポイント上限が定められています（公式案内では要介護4以上が月70ポイント、要介護3が47ポイント、要介護2が35ポイント、身体障害者手帳該当者が70ポイント相当などと案内）。入院等で区支給のおむつを利用できない場合の使用料助成は、令和7年4月以降の使用分で要介護4以上が月額10,000円、要介護3が7,000円、要介護2が5,000円、身体障害者手帳該当者が月額10,000円などと案内されています。金額・支給量は年度や区の規定で変わり得るため、最新の内容は公式でご確認ください。', '随時受付（明確な締切の記載は確認できませんでした）。詳細は公式窓口でご確認ください。', '「高齢者等福祉サービス申請書」と「生活状況票」に記入して申請します（郵送可）。詳細・最新の手続きは葛飾区の公式案内・窓口でご確認ください。', '公式案内では、申請書（高齢者等福祉サービス申請書）および生活状況票が必要とされています。住所地特例該当者は要介護度を確認できる書類、前年1月1日に他自治体に住所があった場合は住民税（課税・非課税）証明書などが必要になる場合があります。必要書類は対象区分により異なるため公式でご確認ください。', FALSE, '葛飾区 高齢者支援課 在宅サービス係（障害のある方の窓口は障害福祉課 障害事業係）', '03-5654-8299', 'https://www.city.katsushika.lg.jp/kenkou/1000052/1030186/1002141/1002160.html', 'https://www.city.katsushika.lg.jp/kenkou/1000052/1030186/1002141/1002160.html', 'おむつの支給・使用料の助成｜葛飾区公式サイト', '2026-06-24', 'high', ARRAY['benefitAmountText', 'targetPeople', 'requiredDocumentsText', 'applicationDeadlineText']::text[], '対象要件・支給量・助成金額・申請方法は葛飾区の規定により定められ、年度で改定されることがあります。本内容は確認日時点の公式案内に基づく概要であり、受給を確約するものではありません。実際の可否・内容は必ず葛飾区の公式窓口でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
