insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot elderly-diapers import', '{"slug":"tokyo-katsushika-elderly-diapers","status":"published","title":"葛飾区 おむつの支給・使用料の助成（紙おむつ支給事業）","officialUrl":"https://www.city.katsushika.lg.jp/kenkou/1000052/1030186/1002141/1002160.html","topic":"elderly-diapers"}'::jsonb, 'pilot:tokyo-katsushika-elderly-diapers:dG9reW8ta2F0c3VzaGlrYS1lbGRlcmx5LWRpYXBl' from public.support_programs sp where sp.slug='tokyo-katsushika-elderly-diapers' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'edogawa'), 'tokyo-edogawa-elderly-diapers', '紙おむつ・防水シーツの支給（高齢者等）', '江戸川区が、在宅で紙おむつを常時必要とする高齢者・要介護者などを対象に、紙おむつや防水シーツを現物支給する区独自の制度です。公式によると、紙おむつは1人900点（9,000円分相当）まで、1割の自己負担で利用できます（防水シーツは年度内1回・2枚を1割負担）。なお、入院中に病院へ持ち込めないおむつ代を対象とする「おむつ使用料の助成（高齢者等）」は別制度で、同月内の併用はできません。', '江戸川区にお住まいで在宅介護を受けている高齢者などの方に、区が紙おむつや防水シーツを届けてくれる制度です。紙おむつは9,000円分まで、自己負担は1割（約900円分）で利用できます。申請はインターネットや、区役所の介護保険課などの窓口でできます。対象になるかどうかは年齢や要介護度などの条件があるため、まずは公式ページや窓口でご確認ください。入院中のおむつ代については別の助成制度があります。', 'service', '公式によると、対象となる可能性があるのは、在宅で紙おむつを常時必要とする方のうち、40歳以上で要介護4または5の方、もしくは医師の意見書により必要性が認められた40歳以上の要支援1～2・要介護1～3の方、および65歳以上で同様に認められた方です。対象や要件の詳細は変わる場合があるため、公式ページでご確認ください。', '公式によると、紙おむつは1人900点（9,000円分相当）まで1割の自己負担で利用でき、防水シーツは年度内1回（2枚）を1割負担で支給されます。点数・金額・自己負担割合は変更される可能性があるため、最新の内容は公式でご確認ください。', '随時受付（公式に明確な締切の記載は確認できませんでした）。最新の取り扱いは公式でご確認ください。', '公式によると、電子申請フォームによるインターネット申請のほか、介護保険被保険者証を持参して窓口（江戸川区福祉部介護保険課相談係ほか）で申請できます。詳細・最新の手続きは公式ページでご確認ください。', '公式によると、介護保険被保険者証と、要件に応じた医師の意見書が必要とされています（令和8年3月31日以前から継続して受給している方は意見書が不要となる場合があります）。必要書類は変更される可能性があるため、公式でご確認ください。', TRUE, '江戸川区 福祉部 介護保険課 相談係', '03-3652-1151', 'https://www.city.edogawa.tokyo.jp/e040/kenko/fukushikaigo/jukunen/kaigo/kamiomutsu.html', 'https://www.city.edogawa.tokyo.jp/e040/kenko/fukushikaigo/jukunen/kaigo/kamiomutsu.html', '紙おむつ・防水シーツの支給（高齢者等） 江戸川区ホームページ', '2026-06-24', 'high', ARRAY['benefitAmountText', 'applicationDeadlineText', 'requiredDocumentsText', 'targetPeople', 'contactPhone']::text[], '本情報は公式ページ（確認日2026-06-24）に基づく概要です。金額・対象要件・自己負担割合・支給量などは年度や制度改定により変わる場合があります。必ず江戸川区の公式ページおよび窓口で最新情報をご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
