insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.chiyoda.lg.jp/koho/kenko/koresha/dokuji-kaigo/kami.html', '敵対的検証を実施（確認日2026-06-24）。program.officialUrl（https://www.city.chiyoda.lg.jp/koho/kenko/koresha/dokuji-kaigo/kami.html）をWebFetchで再取得し、一次調査の妥当性を全項目点検した。(a)到達=OK。(b)許可ホスト=www.city.chiyoda.lg.jpは.lg.jpの千代田区公式ドメインで合格。(c)当該区ページ=高齢者・要介護者向け「紙おむつ」制度そのもののページで合致。(d)現行性=ページ更新日「2026年4月15日」、受付終了・古い年度PDFの記載なし。(e)国制度の誤認なし=千代田区独自の現物支給/現金助成制度。(f)対象の一部を全体と書いていない=在宅(現物支給)と入院・入所中(現金助成)の両区分を本文・フィールドで反映済み。(g)複数制度の混在なし=別ページの障害者向け紙おむつ支給制度は正しく対象外とし、高齢者・要介護者向け単一制度に限定。(h)非断定=金額(月額上限10,600円・税込／1割負担、超過全額自己負担、生活保護世帯は10,600円以内無' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='chiyoda' and t.slug='elderly-diapers' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.chuo.lg.jp/a0028/kenkouiryou/koureikaigo/zaitakuiryou/zaitakushienservice/nintei/omutu.html', 'WebFetchでprogram.officialUrl（www.city.chuo.lg.jp、.lg.jpの許可ホスト）を直接取得し全項目を検証。(a)到達OK (b)許可ホスト一致（.lg.jp）(c)中央区公式の「紙おむつ等支給」当該区ページ (d)掲載日2026-04-01・受付中 (e)国制度誤認なし=区独自制度と明記 (f)対象記述は公式の要件（要介護2以上・常時寝たきりor認知症で失禁・施設未入所）と一致 (g)現物支給と指定おむつ代助成（月7,000円限度）は同一公式ページ上の単一「紙おむつ等支給」制度の2モードで混在ではない (h)金額（40〜70点・1点100円、負担は世帯税区分で変動）は概括＋公式確認の非断定表現。問い合わせ先「福祉保健部高齢者福祉課高齢者サービス係 03-3546-5355」も公式と一致。是正不要、ok=true。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='chuo' and t.slug='elderly-diapers' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.minato.tokyo.jp/zaitakushien/kenko/fukushi/koresha/sekatsu/kamiomutsu.html', '敵対的検証を実施。program.officialUrl（https://www.city.minato.tokyo.jp/zaitakushien/kenko/fukushi/koresha/sekatsu/kamiomutsu.html）をWebFetchで再取得し一次調査の主要事実を独立確認した。(a)到達=200で到達。(b)許可ホスト=www.city.minato.tokyo.jp は .tokyo.jp かつ city.* に合致し許可ホスト（FAQ専用ドメイン等ではない）。(c)当該区ページ=制度名「高齢者紙おむつの給付」で港区の紙おむつ現物支給そのものの公式ページ。(d)現行性=ページ更新日2026年3月30日で現行版。受付終了・古い年度PDFではない。(e)国制度誤認なし=港区独自の在宅高齢者向け現物支給制度であり、国の一般説明ではない。(f)対象の部分=全体の誤記なし=本programは在宅制度を主とし、医療機関入院中・施設入所者は対象外として別制度「おむつ代の助成」へ誘導する旨を明記。(g)複数制度の混在なし=主制度は在宅現物支給の単一制度として記述し、入院・入' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='minato' and t.slug='elderly-diapers' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
