insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.adachi.tokyo.jp/k-fukushi/kaigohokengai.html', '敵対的検証を実施。program.officialUrl（https://www.city.adachi.tokyo.jp/k-fukushi/kaigohokengai.html）をWebFetchで2回取得し、以下を確認した。(a)到達=200で現行（ページ更新日2026-06-17）。(b)許可ホスト=www.city.adachi.tokyo.jp は .tokyo.jp / city.* に一致しFAQ専用ドメインではない。(c)当該区ページ=足立区独自の「高齢者紙おむつの支給」制度本文が掲載されている。(d)古い年度PDF/受付終了でない=現行版。(e)国制度の一般説明ではなく足立区の介護保険外高齢者サービス一覧内の区独自制度。(f)対象の一部を全体と誤記していない=対象（要介護2・3・4・5かつ常時失禁）・対象外（生活保護受給者/中国帰国者支援給付受給者/介護保険施設入所者）を正しく記載。(g)複数制度の混在なし=同ページには高齢者向け14サービスが並ぶが、program本文は「高齢者紙おむつの支給」のみを抽出しており、障がい者向け紙おむつ制度は別制度として正しく区別して' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='adachi' and t.slug='elderly-diapers' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.katsushika.lg.jp/kenkou/1000052/1030186/1002141/1002160.html', 'WebFetchで program.officialUrl（https://www.city.katsushika.lg.jp/kenkou/1000052/1030186/1002141/1002160.html）を検証。(a)到達OK (b)許可ホスト=www.city.katsushika.lg.jp（.lg.jp）一致 (c)当該区の「おむつの支給・使用料の助成」ページで現物配送＋使用料助成の単一制度を確認 (d)令和7年4月以降の助成額・令和8年(2025-04-06)更新で現行・受付終了でない (e)区独自制度（国制度の誤認なし）。
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.edogawa.tokyo.jp/e040/kenko/fukushikaigo/jukunen/kaigo/kamiomutsu.html', '公式ページ（city.edogawa.tokyo.jp＝許可ホスト.tokyo.jp一致）をWebFetchで検証。当該区の紙おむつ・防水シーツ現物支給制度の専用ページであり、更新日2026-04-02・受付終了表示なしの現行ページ。支給量900点（9,000円分相当）・1割自己負担、防水シーツ年度内1回2枚（1割負担）、対象（40歳以上・要介護度別＋医師意見書要件、在宅）、申請（電子申請／窓口）、必要書類は本文と一致。是正点=入院時の別制度「おむつ使用料の助成（上限月額8,100円）」が一次調査のsummary/benefitAmountTextに混入していたため、本制度単体に是正（同月併用不可の別制度として概況のみ）。contactPhoneは公式に専用番号の記載がなく区代表番号のみ。区差のある金額・要介護度・支給量は概括し「公式で確認」を明記。非断定で現行・単一制度・許可ホスト一致のため ok=true。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='edogawa' and t.slug='elderly-diapers' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
